    "companyContextTitle": "Company Context",
    "companyNameLabel": "Company Name *",
    "companyNamePlaceholder": "e.g., TechCorp",
    "productServiceLabel": "Product/Service *",
    "productServicePlaceholder": "e.g., SaaS productivity platform",
    "timelineLabel": "Timeline/Context",
    "timelinePlaceholder": "e.g., Q2 2025, launching new feature",
    "sessionTypeLabel": "Session Type",
    "teamGoalsLabel": "Team Goals & Objectives *",
    "teamGoalsPlaceholder": "e.g., Increase user engagement by 40%, reduce churn rate, improve onboarding experience...",
    "generateIdeasButton": "Generate Ideas",
    "generatingIdeasButton": "Generating Ideas...",
    "requiredFieldsError": "Please fill in all required fields",
    "generateIdeasError": "Failed to generate ideas. Please try again.",
    "aiUnderstandingTitle": "AI Understanding Summary",
    "generatedIdeasTitle": "Generated Ideas",
    "priorityLabel": "Priority:",
    "effortLabel": "Effort:",
    "impactLabel": "Impact:",
    "sessionTypeProductDevelopment": "Product Development",
    "sessionTypeMarketing": "Marketing Strategy",
    "sessionTypeGrowth": "Growth & Expansion",
    "sessionTypeInnovation": "Innovation & R&D",
    "sessionTypeCustomerExperience": "Customer Experience",
    "sessionTypeOperations": "Operations & Process",
    "priorityHigh": "High",
    "priorityMedium": "Medium",
    "priorityLow": "Low",
    "effortHigh": "High",
    "effortMedium": "Medium",
    "effortLow": "Low",
    "impactHigh": "High",
    "impactMedium": "Medium",
    "impactLow": "Low",
    "fallbackIdeaTitle1": "Customer Feedback Integration",
    "fallbackIdeaDescription1": "Implement a systematic approach to collect and analyze customer feedback to drive product improvements and feature prioritization.",
    "fallbackIdeaTitle2": "Cross-functional Collaboration",
    "fallbackIdeaDescription2": "Establish regular cross-team workshops to break down silos and foster innovation through diverse perspectives.",
    "fallbackIdeaTitle3": "Rapid Prototyping Framework",
    "fallbackIdeaDescription3": "Create a streamlined process for quickly testing new ideas and concepts before full development investment.",
    "fallbackIdeaTitle4": "Market Research Initiative",
    "fallbackIdeaDescription4": "Conduct comprehensive market analysis to identify emerging trends and opportunities in your industry.",
    "fallbackIdeaTitle5": "Performance Metrics Dashboard",
    "fallbackIdeaDescription5": "Develop key performance indicators and tracking systems to measure progress toward team goals.",
    "fallbackIdeaTitle6": "Innovation Time Allocation",
    "fallbackIdeaDescription6": "Dedicate specific time blocks for team members to explore creative solutions and experimental projects."
  },
  /* LOCALE_PLACEHOLDER_START */
  "es-ES": {
    "appTitle": "Herramienta de Lluvia de Ideas con IA",
    "appDescription": "Genera ideas contextuales y accionables adaptadas específicamente a tu empresa y objetivos",
    "companyContextTitle": "Contexto de la Empresa",
    "companyNameLabel": "Nombre de la Empresa *",
    "companyNamePlaceholder": "ej., TechCorp",
    "productServiceLabel": "Producto/Servicio *",
    "productServicePlaceholder": "ej., plataforma SaaS de productividad",
    "timelineLabel": "Cronograma/Contexto",
    "timelinePlaceholder": "ej., Q2 2025, lanzando nueva funcionalidad",
    "sessionTypeLabel": "Tipo de Sesión",
    "teamGoalsLabel": "Objetivos y Metas del Equipo *",
    "teamGoalsPlaceholder": "ej., Aumentar la participación del usuario en un 40%, reducir la tasa de abandono, mejorar la experiencia de incorporación...",
    "generateIdeasButton": "Generar Ideas",
    "generatingIdeasButton": "Generando Ideas...",
    "requiredFieldsError": "Por favor, completa todos los campos obligatorios",
    "generateIdeasError": "Error al generar ideas. Por favor, inténtalo de nuevo.",
    "aiUnderstandingTitle": "Resumen de Comprensión de IA",
    "generatedIdeasTitle": "Ideas Generadas",
    "priorityLabel": "Prioridad:",
    "effortLabel": "Esfuerzo:",
    "impactLabel": "Impacto:",
    "sessionTypeProductDevelopment": "Desarrollo de Producto",
    "sessionTypeMarketing": "Estrategia de Marketing",
    "sessionTypeGrowth": "Crecimiento y Expansión",
    "sessionTypeInnovation": "Innovación e I+D",
    "sessionTypeCustomerExperience": "Experiencia del Cliente",
    "sessionTypeOperations": "Operaciones y Procesos",
    "priorityHigh": "Alta",
    "priorityMedium": "Media",
    "priorityLow": "Baja",
    "effortHigh": "Alto",
    "effortMedium": "Medio",
    "effortLow": "Bajo",
    "impactHigh": "Alto",
    "impactMedium": "Medio",
    "impactLow": "Bajo",
    "fallbackIdeaTitle1": "Integración de Comentarios del Cliente",
    "fallbackIdeaDescription1": "Implementar un enfoque sistemático para recopilar y analizar comentarios de clientes para impulsar mejoras de productos y priorización de funcionalidades.",
    "fallbackIdeaTitle2": "Colaboración Interfuncional",
    "fallbackIdeaDescription2": "Establecer talleres regulares entre equipos para romper silos y fomentar la innovación a través de perspectivas diversas.",
    "fallbackIdeaTitle3": "Marco de Prototipado Rápido",
    "fallbackIdeaDescription3": "Crear un proceso simplificado para probar rápidamente nuevas ideas y conceptos antes de la inversión completa en desarrollo.",
    "fallbackIdeaTitle4": "Iniciativa de Investigación de Mercado",
    "fallbackIdeaDescription4": "Realizar un análisis integral del mercado para identificar tendencias emergentes y oportunidades en tu industria.",
    "fallbackIdeaTitle5": "Panel de Métricas de Rendimiento",
    "fallbackIdeaDescription5": "Desarrollar indicadores clave de rendimiento y sistemas de seguimiento para medir el progreso hacia los objetivos del equipo.",
    "fallbackIdeaTitle6": "Asignación de Tiempo para Innovación",
    "fallbackIdeaDescription6": "Dedicar bloques de tiempo específicos para que los miembros del equipo exploren soluciones creativas y proyectos experimentales."
  }
  /* LOCALE_PLACEHOLDER_END */
};

const appLocale = '{{APP_LOCALE}}';
const browserLocale = navigator.languages?.[0] || navigator.language || 'en-US';
const findMatchingLocale = (locale) => {
  if (TRANSLATIONS[locale]) return locale;
  const lang = locale.split('-')[0];
  const match = Object.keys(TRANSLATIONS).find(key => key.startsWith(lang + '-'));
  return match || 'en-US';
};
const locale = (appLocale !== '{{APP_LOCALE}}') ? findMatchingLocale(appLocale) : findMatchingLocale(browserLocale);
const t = (key) => TRANSLATIONS[locale]?.[key] || TRANSLATIONS['en-US'][key] || key;

const BrainstormingTool = () => {
  const [formData, setFormData] = useState({
    companyName: '',
    productService: '',
    timeline: '',
    teamGoals: '',
    sessionType: 'product-development'
  });

  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [error, setError] = useState(null);

  const sessionTypes = [
    { value: 'product-development', label: t('sessionTypeProductDevelopment') },
    { value: 'marketing', label: t('sessionTypeMarketing') },
    { value: 'growth', label: t('sessionTypeGrowth') },
    { value: 'innovation', label: t('sessionTypeInnovation') },
    { value: 'customer-experience', label: t('sessionTypeCustomerExperience') },
    { value: 'operations', label: t('sessionTypeOperations') }
  ];

  const handleInputChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const generateIdeas = async () => {
    if (!formData.companyName || !formData.productService || !formData.teamGoals) {
      setError(t('requiredFieldsError'));
      return;
    }

    setLoading(true);
    setError(null);

    try {
      // First, get Claude's understanding of the company
      const understandingPrompt = `
        Please respond in ${locale} language.

        Analyze this company context and provide a brief understanding summary:

        Company: ${formData.companyName}
        Product/Service: ${formData.productService}
        Timeline: ${formData.timeline}
        Team Goals: ${formData.teamGoals}
        Session Type: ${formData.sessionType}

        Provide a 2-3 sentence summary that shows you understand:
        1. What the company does
        2. Their current context/challenges
        3. What they're trying to achieve

        Then generate 6 specific, actionable brainstorming ideas for ${formData.sessionType} that are directly relevant to this company's context. 

        For each idea, provide:
        - Title (concise, under 8 words)
        - Description (2-3 sentences explaining the idea)
        - Priority (High/Medium/Low)
        - Effort (Low/Medium/High) 
        - Impact (Low/Medium/High)

        Format as JSON:
        {
          "understanding": "Your understanding summary here",
          "ideas": [
            {
              "title": "Idea Title",
              "description": "Detailed description",
              "priority": "High",
              "effort": "Medium",
              "impact": "High"
            }
          ]
        }

        Make sure ideas are specific to their industry, company size, and goals - not generic templates.
      `;

      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 2000,
          messages: [
            { role: "user", content: understandingPrompt }
          ]
        })
      });

      if (!response.ok) {
        throw new Error('Failed to generate ideas');
      }

      const data = await response.json();
      let responseText = data.content[0].text;

      // Clean up the response to extract JSON
      responseText = responseText.replace(/```json\n?/g, "").replace(/```\n?/g, "").trim();

      const parsedResults = JSON.parse(responseText);
      setResults(parsedResults);

    } catch (err) {
      console.error('Error generating ideas:', err);
      setError(t('generateIdeasError'));

      // Fallback results
      setResults({
        understanding: `Based on the information provided, ${formData.companyName} appears to be focused on ${formData.productService} with goals around ${formData.teamGoals}. This context suggests opportunities for ${formData.sessionType} initiatives.`,
        ideas: [
          {
            title: t('fallbackIdeaTitle1'),
            description: t('fallbackIdeaDescription1'),
            priority: "High",
            effort: "Medium",
            impact: "High"
          },
          {
            title: t('fallbackIdeaTitle2'),
            description: t('fallbackIdeaDescription2'),
            priority: "Medium",
            effort: "Low",
            impact: "Medium"
          },
          {
            title: t('fallbackIdeaTitle3'),
            description: t('fallbackIdeaDescription3'),
            priority: "High",
            effort: "Medium",
            impact: "High"
          },
          {
            title: t('fallbackIdeaTitle4'),
            description: t('fallbackIdeaDescription4'),
            priority: "Medium",
            effort: "High",
            impact: "High"
          },
          {
            title: t('fallbackIdeaTitle5'),
            description: t('fallbackIdeaDescription5'),
            priority: "Medium",
            effort: "Medium",
            impact: "Medium"
          },
          {
            title: t('fallbackIdeaTitle6'),
            description: t('fallbackIdeaDescription6'),
            priority: "Low",
            effort: "Low",
            impact: "Medium"
          }
        ]
      });
    }

    setLoading(false);
  };

  const getPriorityColor = (priority) => {
    switch(priority) {
      case 'High': 
      case 'Alta': return 'bg-red-100 text-red-800';
      case 'Medium': 
      case 'Media': return 'bg-yellow-100 text-yellow-800';
      case 'Low': 
      case 'Baja': return 'bg-green-100 text-green-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getEffortColor = (effort) => {
    switch(effort) {
      case 'High': 
      case 'Alto': return 'bg-purple-100 text-purple-800';
      case 'Medium': 
      case 'Medio': return 'bg-blue-100 text-blue-800';
      case 'Low': 
      case 'Bajo': return 'bg-cyan-100 text-cyan-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getImpactColor = (impact) => {
    switch(impact) {
      case 'High': 
      case 'Alto': return 'bg-emerald-100 text-emerald-800';
      case 'Medium': 
      case 'Medio': return 'bg-orange-100 text-orange-800';
      case 'Low': 
      case 'Bajo': return 'bg-slate-100 text-slate-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-50 via-white to-purple-50 p-6">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="text-center mb-12">
          <div className="flex justify-center mb-4">
            <div className="bg-gradient-to-r from-indigo-600 to-purple-600 p-3 rounded-full">
              <Lightbulb className="w-8 h-8 text-white" />
            </div>
          </div>
          <h1 className="text-4xl font-bold text-gray-900 mb-4">
            {t('appTitle')}
          </h1>
          <p className="text-lg text-gray-600 max-w-2xl mx-auto">
            {t('appDescription')}
          </p>
        </div>

        {/* Form */}
        <div className="bg-white rounded-2xl shadow-xl p-8 mb-8">
          <h2 className="text-2xl font-semibold text-gray-900 mb-6 flex items-center">
            <Building className="w-6 h-6 mr-3 text-indigo-600" />
            {t('companyContextTitle')}
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                {t('companyNameLabel')}
              </label>
              <input
                type="text"
                name="companyName"
                value={formData.companyName}
                onChange={handleInputChange}
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                placeholder={t('companyNamePlaceholder')}
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                {t('productServiceLabel')}
              </label>
              <input
                type="text"
                name="productService"
                value={formData.productService}
                onChange={handleInputChange}
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                placeholder={t('productServicePlaceholder')}
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                {t('timelineLabel')}
              </label>
              <input
                type="text"
                name="timeline"
                value={formData.timeline}
                onChange={handleInputChange}
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                placeholder={t('timelinePlaceholder')}
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                {t('sessionTypeLabel')}
              </label>
              <select
                name="sessionType"
                value={formData.sessionType}
                onChange={handleInputChange}
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
              >
                {sessionTypes.map(type => (
                  <option key={type.value} value={type.value}>
                    {type.label}
                  </option>
                ))}
              </select>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                {t('teamGoalsLabel')}
              </label>
              <textarea
                name="teamGoals"
                value={formData.teamGoals}
                onChange={handleInputChange}
                rows={4}
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                placeholder={t('teamGoalsPlaceholder')}
              />
            </div>
          </div>

          {error && (
            <div className="mt-4 p-4 bg-red-50 border border-red-200 rounded-lg flex items-center">
              <AlertCircle className="w-5 h-5 text-red-500 mr-2" />
              <p className="text-red-700">{error}</p>
            </div>
          )}

          <div className="mt-8 text-center">
            <button
              onClick={generateIdeas}
              disabled={loading}
              className="bg-gradient-to-r from-indigo-600 to-purple-600 text-white px-8 py-3 rounded-lg font-semibold hover:from-indigo-700 hover:to-purple-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-200 flex items-center justify-center mx-auto"
            >
              {loading ? (
                <>
                  <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white mr-2"></div>
                  {t('generatingIdeasButton')}
                </>
              ) : (
                <>
                  <Zap className="w-5 h-5 mr-2" />
                  {t('generateIdeasButton')}
                </>
              )}
            </button>
          </div>
        </div>

        {/* Results */}
        {results && (
          <div className="space-y-8">
            {/* Understanding Summary */}
            <div className="bg-gradient-to-r from-blue-50 to-indigo-50 rounded-2xl p-6 border border-blue-200">
              <h3 className="text-xl font-semibold text-gray-900 mb-4 flex items-center">
                <Target className="w-6 h-6 mr-3 text-blue-600" />
                {t('aiUnderstandingTitle')}
              </h3>
              <p className="text-gray-700 leading-relaxed">
                {results.understanding}
              </p>
            </div>

            {/* Ideas Grid */}
            <div>
              <h3 className="text-2xl font-semibold text-gray-900 mb-6">
                {t('generatedIdeasTitle')}
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {results.ideas.map((idea, index) => (
                  <div
                    key={index}
                    className="bg-white rounded-xl shadow-lg hover:shadow-xl transition-shadow duration-300 overflow-hidden border border-gray-100"
                  >
                    <div className="p-6">
                      <h4 className="text-lg font-semibold text-gray-900 mb-3">
                        {idea.title}
                      </h4>
                      <p className="text-gray-600 mb-4 leading-relaxed">
                        {idea.description}
                      </p>

                      <div className="space-y-3">
                        <div className="flex items-center justify-between">
                          <span className="text-sm font-medium text-gray-500">{t('priorityLabel')}</span>
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getPriorityColor(idea.priority)}`}>
                            {idea.priority}
                          </span>
                        </div>

                        <div className="flex items-center justify-between">
                          <span className="text-sm font-medium text-gray-500 flex items-center">
                            <Clock className="w-4 h-4 mr-1" />
                            {t('effortLabel')}
                          </span>
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getEffortColor(idea.effort)}`}>
                            {idea.effort}
                          </span>
                        </div>

                        <div className="flex items-center justify-between">
                          <span className="text-sm font-medium text-gray-500 flex items-center">
                            <TrendingUp className="w-4 h-4 mr-1" />
                            {t('impactLabel')}
                          </span>
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getImpactColor(idea.impact)}`}>
                            {idea.impact}
                          </span>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default BrainstormingTool;
